import{_ as d,o as a,c as e,ag as r}from"./chunks/framework.ePeAWSvT.js";const p="/images/image_011.png",n="/images/image_012.png",i="/images/image_013.png",o="/images/image_014.png",s="/images/image_015.png",l="/images/image_016.png",m="/images/image_017.png",g="/images/image_018.png",h="/images/image_019.png",c="/images/image_020.png",P="/images/image_021.png",_="/images/image_022.png",b="/images/image_023.png",u="/images/image_024.png",C="/images/image_025.png",S="/images/image_026.png",L=JSON.parse('{"title":"监控","description":"","frontmatter":{},"headers":[],"relativePath":"guide/monitor/index.md","filePath":"guide/monitor/index.md","lastUpdated":null}'),x={name:"guide/monitor/index.md"};function q(A,t,D,M,f,T){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="监控" tabindex="-1">监控 <a class="header-anchor" href="#监控" aria-label="Permalink to &quot;监控&quot;">​</a></h1><h2 id="概况" tabindex="-1">概况 <a class="header-anchor" href="#概况" aria-label="Permalink to &quot;概况&quot;">​</a></h2><p>在导航栏里点击【监控】【概况】，进入概览界面，如图2-1所示。概览界面分为3个部分，分别为“系统信息”，“面板端口”，“流量”。</p><p>（1）在“系统信息”页面，可以看到设备的产品型号、序列号、MAC地址、软硬件版本等信息，具体参数说明如表2-1所示。</p><p><img src="'+p+'" alt="系统基本信息"></p><p align="center"><em>图2-1 系统基本信息</em></p><p><strong>表2-1 基本信息参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>产品型号</td><td>用以指示该设备的产品型号</td></tr><tr><td>产品序列号</td><td>用以指示该设备的产品序列号</td></tr><tr><td>MAC地址</td><td>用以指示该设备的MAC地址</td></tr><tr><td>硬件版本</td><td>用以指示该设备的硬件版本号</td></tr><tr><td>软件版本</td><td>用以指示该设备的软件版本号</td></tr><tr><td>运行时间</td><td>用以指示该设备最近一次启动后连续运行的时长，设备重启后将重新计时</td></tr><tr><td>CPU</td><td>用以显示当前CPU的占用率</td></tr><tr><td>内存</td><td>用以显示当前系统可用内存</td></tr></tbody></table><p>（2）“面板端口”页面，可以看到设备的面板示意图以及面板端口的工作情况。</p><p>（3）“流量”页面，可以观察到端口的流量情况。</p><h2 id="端口统计" tabindex="-1">端口统计 <a class="header-anchor" href="#端口统计" aria-label="Permalink to &quot;端口统计&quot;">​</a></h2><p>“端口统计”页面用于显示端口接收和发送报文数量的相关统计信息。</p><p>（1）在导航栏中选择【监控】【端口统计】，进入端口统计页面，如图2-2所示。</p><p>（2）在页面中查看设备端口接收和发送负载、端口速率，错误报文统计，具体参数说明如表2-2所描述。</p><p>（3）点击端口最后的【清除】按钮可以清除端口计数。</p><p>（4）点击【端口配置】按钮可以直接切换到端口配置界面。</p><p><img src="'+n+'" alt="端口统计页面"></p><p align="center"><em>图2-2 端口统计页面</em></p><p><strong>表2-2 参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>端口</td><td>交换机的端口</td></tr><tr><td>接收负载</td><td>端口接收负载率</td></tr><tr><td>发送负载</td><td>端口发送负载率</td></tr><tr><td>速率</td><td>端口工作速率</td></tr><tr><td>不完整数据包</td><td>端口接收的报文小于64字节的数量</td></tr><tr><td>过大数据包</td><td>端口接收的报文大于MTU配置上限的数量</td></tr><tr><td>CRC错误</td><td>端口的接收的CRC校验错误的报文数量</td></tr><tr><td>冲突次数</td><td>端口的接收的冲突报文数量</td></tr><tr><td>清除</td><td>报文清零</td></tr></tbody></table><h2 id="环路保护" tabindex="-1">环路保护 <a class="header-anchor" href="#环路保护" aria-label="Permalink to &quot;环路保护&quot;">​</a></h2><p>“环路保护”页面用于显示设备环路相关协议的工作状态，如ERPS和生成树协议。</p><p>（1）在导航栏中选择【监控】【环路保护】，进入环路保护状态页面，如图2-3所示。</p><p>（2）在页面中可以看到已经开启的ERPS和生成树协议工作状态，具体参数说明见协议相关章节。</p><p>（3）点击【ERPS配置】、【生成树配置】按钮可以直接切换到相关配置界面。</p><p><img src="'+i+'" alt="环路保护状态"></p><p align="center"><em>图2-3 环路保护状态</em></p><h2 id="安全" tabindex="-1">安全 <a class="header-anchor" href="#安全" aria-label="Permalink to &quot;安全&quot;">​</a></h2><p>“安全”页面用于显示设备安全相关协议的工作状态，有端口安全，IP Source Guard，MAC认证三个部分。</p><p>（1）在导航栏中选择【监控】【安全】，进入安全显示页面，如图2-4，图2-5，图2-6所示。</p><p><img src="'+o+'" alt="端口安全状态"></p><p align="center"><em>图2-4 端口安全状态</em></p><p><img src="'+s+'" alt="IP Source Guard状态"></p><p align="center"><em>图2-5 IP Source Guard状态</em></p><p><img src="'+l+'" alt="MAC认证状态"></p><p align="center"><em>图2-6 MAC认证状态</em></p><p>（2）在页面中可以看到已经开启的端口安全、IP Source Guard、MAC认证工作状态，具体参数说明见协议相关章节。</p><p>（3）点击对应的配置按钮可以直接切换到相关配置界面。</p><h2 id="poe状态" tabindex="-1">PoE状态 <a class="header-anchor" href="#poe状态" aria-label="Permalink to &quot;PoE状态&quot;">​</a></h2><p>“PoE状态”页面用于显示设备当前PoE工作状态。</p><p>（1）在导航栏中选择【监控】【PoE状态】，进入PoE状态页面，如图2-7所示。</p><p><img src="'+m+'" alt="PoE状态"></p><p align="center"><em>图2-7 PoE状态</em></p><p>（2）在页面中可以看到设备总的供电功率、供电端口数、每个端口的供电状态。具体参数说明，如表格2-3所示。</p><p><strong>表2-3 PoE全局配置参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>说明</th></tr></thead><tbody><tr><td>全局状态</td><td>消耗功率(W)</td><td>当前设备PoE对外供电的总功率</td></tr><tr><td>全局状态</td><td>供电端口数</td><td>当前设备对外供电的端口总数</td></tr><tr><td>端口</td><td>名称</td><td>指示面板端口号</td></tr><tr><td>端口</td><td>状态</td><td>PoE目前的供电状态，disable供电关闭状态，enable供电状态</td></tr><tr><td>端口</td><td>描述</td><td>PoE端口描述</td></tr><tr><td>端口</td><td>原因</td><td>端口无法供电的原因， short：负载短路 management：功率不足</td></tr><tr><td>端口</td><td>功率</td><td>当前端口的消耗的功率</td></tr><tr><td>端口</td><td>电流</td><td>当前端口的工作电流</td></tr><tr><td>端口</td><td>分类</td><td>接入此端口PD设备的Class等级</td></tr><tr><td>端口</td><td>管理状态</td><td>显示此端口的PoE功能是使能或禁止</td></tr></tbody></table><p>（3）点击【PoE配置】按钮可以直接切换到PoE配置界面。</p><h2 id="串口服务器状态" tabindex="-1">串口服务器状态 <a class="header-anchor" href="#串口服务器状态" aria-label="Permalink to &quot;串口服务器状态&quot;">​</a></h2><p>“串口服务器状态”页面用于显示设备的串口服务器工作情况。</p><p>（1）在导航栏中选择【监控】【串口服务器状态】，进入串口服务器状态页面，如图2-8所示。</p><p><img src="'+g+'" alt="串口服务器状态"></p><p align="center"><em>图2-8 串口服务器状态</em></p><p>（2）在页面中可以看到串口服务器的报文收发状态，具体参数说明如表格2-4所示。</p><p><strong>表2-4 串口服务器参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>ID</td><td>串口服务器的串口ID号</td></tr><tr><td>Net Octets Rx</td><td>网络端接收字节数</td></tr><tr><td>Net Packets Rx</td><td>网络端接收报文数</td></tr><tr><td>Net Octets Tx</td><td>网络端发送字节数</td></tr><tr><td>Net Packets Tx</td><td>网络端发送报文数</td></tr><tr><td>Serial Octets Rx</td><td>串口端接收字节数</td></tr><tr><td>Serial Packets Rx</td><td>串口端接收报文数</td></tr><tr><td>Serial Octets Tx</td><td>串口端发送字节数</td></tr><tr><td>Serial Packets Tx</td><td>串口端发送报文数</td></tr><tr><td>Net Connect Up/Down times</td><td>网络端连接次数</td></tr><tr><td>Serial Overload Drop Packets</td><td>串口端溢出丢弃报文数</td></tr></tbody></table><p>（3）点击【配置】按钮可以直接切换到串口服务器配置界面。</p><h2 id="lldp状态" tabindex="-1">LLDP状态 <a class="header-anchor" href="#lldp状态" aria-label="Permalink to &quot;LLDP状态&quot;">​</a></h2><p>“LLDP状态”页面用于显示设备LLDP工作状态。</p><p>（1）在导航栏中选择【监控】【LLDP状态】，进入LLDP状态页面，如图2-9所示。</p><p>（2）在页面中可以看到已经开启的LLDP协议工作状态，具体参数说明见协议相关章节。</p><p>（3）点击【LLDP配置】按钮可以直接切换到LLDP配置界面。</p><p><img src="'+h+'" alt="LLDP状态"></p><p align="center"><em>图2-9 LLDP状态</em></p><h2 id="igmp-snooping状态" tabindex="-1">IGMP Snooping状态 <a class="header-anchor" href="#igmp-snooping状态" aria-label="Permalink to &quot;IGMP Snooping状态&quot;">​</a></h2><p>“IGMP Snooping状态”用于显示设备IGMP Snooping协议工作状态。</p><p>（1）在导航栏中选择【监控】【IGMP Snooping状态】，进入IGMP Snooping状态页面，如图2-10所示。</p><p>（2）在页面中可以看到已经开启的IGMP Snooping协议工作状态，具体参数说明见协议相关章节。</p><p>（3）点击【IGMP Snooping配置】按钮可以直接切换到IGMP Snogging配置界面。</p><p><img src="'+c+'" alt="IGMP Snooping状态"></p><p align="center"><em>图2-10 IGMP Snooping状态</em></p><h2 id="dhcp-snooping状态" tabindex="-1">DHCP Snooping状态 <a class="header-anchor" href="#dhcp-snooping状态" aria-label="Permalink to &quot;DHCP Snooping状态&quot;">​</a></h2><p>“DHCP Snooping状态”页面用于显示设备DHCP Snooping协议工作状态。</p><p>（1）在导航栏中选择【监控】【DHCP Snooping状态】，进入DHCP Snooping状态页面，如图2-11所示。</p><p>（2）在页面中可以看到已经开启的DHCP Snooping协议工作状态，具体参数说明见协议相关章节。</p><p>（3）点击【DHCP Snooping配置】按钮可以直接切换到DHCP Snooping配置界面。</p><p><img src="'+P+'" alt="DHCP Snooping状态"></p><p align="center"><em>图2-11 DHCP Snooping状态</em></p><h2 id="qinq信息" tabindex="-1">QinQ信息 <a class="header-anchor" href="#qinq信息" aria-label="Permalink to &quot;QinQ信息&quot;">​</a></h2><p>“QinQ信息”页面用于显示设备QinQ信息工作状态。</p><p>（1）在导航栏中选择【监控】【QinQ信息】，进入QinQ状态页面，如图2-12所示。</p><p>（2）在页面中可以看到已经开启的QinQ工作状态，具体参数说明见协议相关章节。</p><p>（3）点击【QinQ配置】按钮可以迅速切换到QinQ配置界面。</p><p><img src="'+_+'" alt="QinQ信息"></p><p align="center"><em>图2-12 QinQ信息</em></p><h2 id="环路检测状态" tabindex="-1">环路检测状态 <a class="header-anchor" href="#环路检测状态" aria-label="Permalink to &quot;环路检测状态&quot;">​</a></h2><p>“环路检测状态”页面用于显示设备端口环路状态。</p><p>（1）在导航栏中选择【监控】【环路检测状态】，进入环路检测状态页面，如图2-13所示。</p><p>（2）在页面中可以看到设备端口的环路状态，具体参数说明见协议相关章节。</p><p>（3）点击【环路检测配置】按钮可以迅速切换到环路检测配置界面。</p><p><img src="'+b+'" alt="环路检测状态"></p><p align="center"><em>图2-13 环路检测状态</em></p><h2 id="mac地址表" tabindex="-1">MAC地址表 <a class="header-anchor" href="#mac地址表" aria-label="Permalink to &quot;MAC地址表&quot;">​</a></h2><p>“MAC地址表”页面用于显示设备MAC地址表项信息。</p><p>（1）在导航栏中选择【监控】【MAC地址表】，进入MAC地址表页面，如图2-14所示。</p><p>（2）在页面中可以看到设备MAC地址表项信息，具体参数说明见协议相关章节。</p><p>（3）点击【MAC配置】按钮可以迅速切换到MAC地址配置界面。</p><p><img src="'+u+'" alt="MAC地址表信息"></p><p align="center"><em>图2-14 MAC地址表信息</em></p><h2 id="arp-邻居信息" tabindex="-1">ARP/邻居信息 <a class="header-anchor" href="#arp-邻居信息" aria-label="Permalink to &quot;ARP/邻居信息&quot;">​</a></h2><p>“ARP/邻居信息”页面用于显示设备ARP/邻居表项信息。</p><p>（1）在导航栏中选择【监控】【ARP/邻居信息】，进入ARP/邻居状态页面，如图2-15所示。</p><p>（2）在页面中可以看到设备所有的ARP/邻居表项信息，具体参数说明见协议相关章节。</p><p>（3）点击【ARP/邻居配置】按钮可以迅速切换到三层ARP/邻居配置界面。</p><p><img src="'+C+'" alt="ARP/邻居信息"></p><p align="center"><em>图2-15 ARP/邻居信息</em></p><h2 id="ntp状态" tabindex="-1">NTP状态 <a class="header-anchor" href="#ntp状态" aria-label="Permalink to &quot;NTP状态&quot;">​</a></h2><p>“NTP状态”页面用于显示设备NTP表项信息。</p><p>（1）在导航栏中选择【监控】【NTP状态】，进入NTP状态页面，如图2-16所示。</p><p>（2）在页面中可以看到设备所有的NTP表项信息，具体参数说明如表2-5所示。</p><p>（3）点击【NTP配置】按钮可以迅速切换到NTP配置界面。</p><p><img src="'+S+'" alt="NTP状态信息"></p><p align="center"><em>图2-16 NTP状态信息</em></p><p>表 2-5 NTP状态信息参数说明</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>remote</td><td>时钟源主机名或IP地址</td></tr><tr><td>refid</td><td>参考ID</td></tr><tr><td>st</td><td>时钟源阶层</td></tr><tr><td>t</td><td>类型 u: 单播或多播客户端 b: 广播或多播客户端 l: 本地（参考时钟源）</td></tr><tr><td>when</td><td>自上次同步时间到现在的秒/分/时</td></tr><tr><td>poll</td><td>时钟轮询周期（单位：log2 秒）</td></tr><tr><td>reach</td><td>最近8次连续轮询的情况(八进制掩码)</td></tr><tr><td>delay</td><td>网络延迟</td></tr><tr><td>offset</td><td>时钟偏移</td></tr><tr><td>jitter</td><td>时钟抖动</td></tr></tbody></table>',114)])])}const Q=d(x,[["render",q]]);export{L as __pageData,Q as default};
